-- 건축사: 승효상 (ID 64)
INSERT INTO career_trees (id, person_name, person_name_en, person_title, stages_json, display_priority) VALUES (
  64,
  '승효상',
  'Seung H-sang',
  '이로재 건축사무소 대표, 초대 서울시 총괄건축가',
  '[{"order":0,"title":"서울대학교 건축공학과 입학·졸업","organization":"서울대학교 공과대학 건축공학과","years":"1971–1979","description":"1971년 서울대학교 공과대학 건축공학과에 입학하여 1975년 졸업했다. 이후 서울대 건축학과 석사과정을 이수(1979년)하고 오스트리아 빈 공과대학에서 수학했다.","job_slug":null},{"order":1,"title":"공간연구소 실무수련 및 건축사 자격 취득","organization":"김수근 공간연구소","years":"1974–1982","description":"대학 재학 중인 1974년부터 건축가 김수근의 공간연구소에서 설계 실무를 시작했다. 마산 양덕성당, 경동교회 등 주요 작품에 참여하며 건축사 자격을 취득했다.","job_slug":"건축사"},{"order":2,"title":"공간연구소 대표이사 및 오스트리아 연수","organization":"공간연구소 / Marchart Moebius und Partner(빈)","years":"1982–1989","description":"1981~1982년 오스트리아 빈의 마차트 뫼비우스 사무소에서 국제 경험을 쌓은 후 귀국했다. 1982년 공간연구소 대표이사로 취임하고, 1986년 김수근 타계 후 사무소를 이끌며 30억 원의 채무를 전액 청산했다.","job_slug":null},{"order":3,"title":"이로재 건축사무소 설립 및 빈자의 미학 정립","organization":"이로재(履露齋) 건축사무소","years":"1989–2013","description":"1989년 독립 후 이로재를 설립했다. 수졸당(1993), 수백당(1998), 웰콤시티(2000) 등을 설계하며 빈자의 미학 철학을 구축했다. 2002년 국립현대미술관 올해의 작가로 선정되고, 노무현 전 대통령 묘역(2010)을 설계했다.","job_slug":null},{"order":4,"title":"초대 서울시 총괄건축가·국가건축정책위원회 위원장","organization":"서울시청 / 국가건축정책위원회","years":"2014–2020","description":"2014년 초대 서울시 총괄건축가로 선임되어 2016년까지 서울의 공공건축 및 도시 공간 정책을 주도했다. 2018년 국가건축정책위원회 위원장으로 선임되어 2020년까지 공공 건축 행정의 최고 자문 역할을 수행했다.","job_slug":null}]',
  100
);

